import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Box, Card, CardContent, Typography, CircularProgress } from '@mui/material';
import { format } from 'date-fns'; // For date formatting

function EmpEmpDetails() {
  const { user_id } = useParams(); // Extract user_id from the URL
  const [workReports, setWorkReports] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch(`http://localhost:5000/auth/${user_id}/work-reports`);
        const data = await response.json();
        setWorkReports(data); // Set the fetched work reports
        setLoading(false); // Stop loading once data is fetched
      } catch (error) {
        console.error('Error fetching data:', error);
        setLoading(false);
      }
    };

    if (user_id) {
      fetchData(); // Fetch the data only if user_id is available
    }
  }, [user_id]);

  return (
    <Box sx={{ padding: 3 }}>
      <Typography variant="h4">Work Reports for User {user_id}</Typography>

      {loading ? (
        <CircularProgress />
      ) : (
        <Box>
          {workReports.length > 0 ? (
            workReports.map((report) => (
              <Card key={report.id} sx={{ marginBottom: 2 }}>
                <CardContent>
                  <Typography variant="h6">Report ID: {report.id}</Typography>
                  <Typography variant="body2">Date: {format(new Date(report.date), 'MM/dd/yyyy')}</Typography>
                  <Typography variant="body2">Machine Name: {report.machine_name}</Typography>
                  <Typography variant="body2">Nature of Complaint: {report.nature_of_complaint}</Typography>
                </CardContent>
              </Card>
            ))
          ) : (
            <Typography>No work reports found.</Typography>
          )}
        </Box>
      )}
    </Box>
  );
}

export default EmpEmpDetails;
